# variables.tf
variable "principal_id" { type = string }
variable "storage_account_id" { type = string }
variable "container_name" { type = string }
variable "abac_tag_key" { type = string; default = "" }
variable "abac_tag_value" { type = string; default = "" }

# main.tf
data "azurerm_storage_account" "sa" {
  id = var.storage_account_id
}

resource "azurerm_role_assignment" "blob_reader" {
  principal_id         = var.principal_id
  role_definition_name = "Storage Blob Data Reader"
  # Container-level scope — narrower than storage account
  scope = "${var.storage_account_id}/blobServices/default/containers/${var.container_name}"

  # Optional ABAC condition — only applied when tag key/value are provided
  condition         = var.abac_tag_key != "" ? <<-EOT
    (
      !(ActionMatches{"Microsoft.Storage/storageAccounts/blobServices/containers/blobs/read"})
    )
    OR
    (
      @Resource[Microsoft.Storage/storageAccounts/blobServices/containers/blobs/tags:${var.abac_tag_key}<$key_case_insensitive$>]
      StringEqualsIgnoreCase "${var.abac_tag_value}"
    )
  EOT
  : null
  condition_version = var.abac_tag_key != "" ? "2.0" : null
}

// Cross-reference role assignments with actual usage from AzureActivity logs
// First: collect principals that have performed any action in the last 90 days
let ActivePrincipals = AzureActivity
| where TimeGenerated > ago(90d)
| where ActivityStatusValue == 'Success'
| summarize LastAction=max(TimeGenerated) by Caller
| project Caller;

// Then: surface role assignments whose principal has been inactive
// (Requires role assignment data exported via Azure Resource Graph or Policy)
// This query pattern works when role assignment data is joined from an external table
AzureActivity
| where TimeGenerated > ago(1d)
| where OperationNameValue == 'MICROSOFT.AUTHORIZATION/ROLEASSIGNMENTS/WRITE'
| extend AssignedPrincipal = tostring(todynamic(Properties).requestbody)
| join kind=leftanti ActivePrincipals on $left.AssignedPrincipal == $right.Caller
| project TimeGenerated, AssignedPrincipal, ResourceGroup, Caller

# Create a Conditional Access policy for a specific SP
# (Requires Entra ID P1 or P2 + Workload Identities Premium)

ACCESS_TOKEN=$(az account get-access-token \
  --resource https://graph.microsoft.com/ \
  --query accessToken -o tsv)

curl -s -X POST https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies \
  -H "Authorization: Bearer $ACCESS_TOKEN" \
  -H 'Content-Type: application/json' \
  -d '{
    "displayName": "Restrict SP to known IP ranges",
    "state": "enabled",
    "conditions": {
      "applications": { "includeApplications": ["ALL"] },
      "clientApplications": {
        "includeServicePrincipals": ["00000000-0000-0000-0000-000000000000"]
      },
      "locations": { "excludeLocations": ["AllTrusted"] }
    },
    "grantControls": { "operator": "OR", "builtInControls": ["block"] }
  }'
